#include <iostream>
using namespace std;

int main() {
    int matrix[3][3] = {{1,2,3}, {4,5,6}, {7,8,9}};

    // Access individual elements
    cout << "Top-left: " << matrix[0][0] << endl;
    cout << "Center: " << matrix[1][1] << endl;
    cout << "Bottom-right: " << matrix[2][2] << endl;

    // Modify
    matrix[0][1] = 99;
    matrix[2][0] = matrix[1][1] + 10;

    // Row-major traversal
    cout << "Row-major order: ";
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            cout << matrix[i][j] << " ";
        }
    }
    cout << endl;

    // Column-major traversal
    cout << "Column-major order: ";
    for (int j = 0; j < 3; j++) {
        for (int i = 0; i < 3; i++) {
            cout << matrix[i][j] << " ";
        }
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int arr[2][3] = {{1,2,3}, {4,5,6}};
    int* p = &arr[0][0];

    cout << "Memory addresses:" << endl;
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 3; j++) {
            cout << "arr[" << i << "][" << j << "] at " << &arr[i][j] << " = " << arr[i][j] << endl;
        }
    }

    // Can traverse as 1D array (but careful with bounds)
    cout << "As 1D: ";
    for (int i = 0; i < 6; i++) {
        cout << *(p + i) << " ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

// Must specify column count (second dimension)
void printMatrix(int mat[][4], int rows) {
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < 4; j++) {
            cout << mat[i][j] << "\t";
        }
        cout << endl;
    }
}

// Using pointer to array of 4 ints
void multiplyBy2(int (*mat)[4], int rows) {
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < 4; j++) {
            mat[i][j] *= 2;
        }
    }
}

// Template to deduce dimensions (compile-time)
template<size_t rows, size_t cols>
void printTemplate(int (&mat)[rows][cols]) {
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            cout << mat[i][j] << " ";
        }
        cout << endl;
    }
}

int main() {
    int matrix[2][4] = {{1,2,3,4}, {5,6,7,8}};

    printMatrix(matrix, 2);
    multiplyBy2(matrix, 2);
    cout << "After multiplyBy2:" << endl;
    printTemplate(matrix);  // template deduces 2,4

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int rows = 3, cols = 4;

    // Method 1: Array of pointers (each row on heap)
    int** matrix = new int*[rows];
    for (int i = 0; i < rows; i++) {
        matrix[i] = new int[cols];
        for (int j = 0; j < cols; j++) {
            matrix[i][j] = i * cols + j;
        }
    }

    // Access
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            cout << matrix[i][j] << "\t";
        }
        cout << endl;
    }

    // Deallocate (reverse order)
    for (int i = 0; i < rows; i++) {
        delete[] matrix[i];
    }
    delete[] matrix;

    // Method 2: Flat array (single allocation, cache-friendly)
    int* flat = new int[rows * cols];
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            flat[i * cols + j] = i * cols + j;
        }
    }

    // Access flat[i][j] as flat[i*cols + j]
    delete[] flat;

    // Method 3: Using vector of vectors (modern C++, but slower)
    // vector<vector<int>> v(rows, vector<int>(cols));

    return 0;
}

#include <iostream>
using namespace std;

const int ROWS = 2;
const int COLS = 3;

void addMatrices(int A[][COLS], int B[][COLS], int C[][COLS]) {
    for (int i = 0; i < ROWS; i++) {
        for (int j = 0; j < COLS; j++) {
            C[i][j] = A[i][j] + B[i][j];
        }
    }
}

void multiplyMatrices(int A[][COLS], int B[][2], int C[][2], int rA, int cA, int cB) {
    // A: rA x cA, B: cA x cB, C: rA x cB
    for (int i = 0; i < rA; i++) {
        for (int j = 0; j < cB; j++) {
            C[i][j] = 0;
            for (int k = 0; k < cA; k++) {
                C[i][j] += A[i][k] * B[k][j];
            }
        }
    }
}

int main() {
    int A[ROWS][COLS] = {{1,2,3}, {4,5,6}};
    int B[ROWS][COLS] = {{7,8,9}, {10,11,12}};
    int C[ROWS][COLS];

    addMatrices(A, B, C);
    cout << "Sum:" << endl;
    for (int i = 0; i < ROWS; i++) {
        for (int j = 0; j < COLS; j++) {
            cout << C[i][j] << " ";
        }
        cout << endl;
    }

    // Multiplication example
    int X[2][3] = {{1,2,3}, {4,5,6}};
    int Y[3][2] = {{7,8}, {9,10}, {11,12}};
    int Z[2][2];
    multiplyMatrices(X, Y, Z, 2, 3, 2);
    cout << "Product:" << endl;
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 2; j++) {
            cout << Z[i][j] << " ";
        }
        cout << endl;
    }

    return 0;
}

